import{_ as i}from"./plugin-vue_export-helper.21dcd24c.js";import{o as e,c as a,e as n}from"./app.d1ff24bc.js";const l={},s=n('<h2 id="humanities" tabindex="-1"><a class="header-anchor" href="#humanities" aria-hidden="true">#</a> Humanities</h2><p>academic disciplines that study the human condition, using methods that are primarily analytical, critical, or speculative, as distinguished from the mainly empirical approaches of the natural sciences.</p><p>\u7814\u7A76\u4EBA\u7C7B\u7684\u5B66\u79D1\uFF0C\u4F7F\u7528\u4E3B\u8981\u662F\u5206\u6790\u3001\u6279\u5224\u6216\u63A8\u6D4B\u7684\u65B9\u6CD5\uFF0C\u6709\u522B\u4E8E\u81EA\u7136\u79D1\u5B66\u7684\u4E3B\u8981\u7ECF\u9A8C\u65B9\u6CD5\u3002</p><ul><li>Performing arts</li><li>Visual arts</li><li>History</li><li>Languages and literature</li><li>Law</li><li>Philosophy</li><li>Theology</li></ul><h2 id="social-science" tabindex="-1"><a class="header-anchor" href="#social-science" aria-hidden="true">#</a> Social science</h2><p>the sciences concerned with societies, human behaviour, and social relationships.</p><p>\u793E\u4F1A\u79D1\u5B66\u662F\u4E0E\u793E\u4F1A\u3001\u4EBA\u7C7B\u884C\u4E3A\u548C\u793E\u4F1A\u6709\u5173\u7684\u79D1\u5B66\u3002</p><ul><li>Anthropology</li><li>Archaeology</li><li>Economics</li><li>Geography</li><li>Political science</li><li>Psychology</li><li>Sociology</li><li>Social work</li></ul><h2 id="natural-science" tabindex="-1"><a class="header-anchor" href="#natural-science" aria-hidden="true">#</a> Natural science</h2><p>a major branch of scienza that tries to explain, and predict, nature&#39;s phenomena based on empirical evidence. In natural science, hypothesis must be verified scientifically to be regarded as scientific theory. Validity, accuracy, and social mechanisms ensuring quality control, such as peer review and repeatability of findings, are amongst the criteria and methods used for this purpose. Natural science can be broken into 2 main branches: life science, and physical science. Each of these branches, and all of their sub-branches, are referred to as natural sciences.</p><p>\u5176\u4E2D\u4E00\u4E2A\u4E3B\u8981\u5206\u652F\u8BD5\u56FE\u6839\u636E\u7ECF\u9A8C\u8BC1\u636E\u89E3\u91CA\u548C\u9884\u6D4B\u81EA\u7136\u73B0\u8C61\u3002\u5728\u81EA\u7136\u79D1\u5B66\u4E2D\uFF0C\u5047\u8BBE\u5FC5\u987B\u7ECF\u8FC7\u79D1\u5B66\u9A8C\u8BC1\u624D\u80FD\u88AB\u89C6\u4E3A \u3002\u6709\u6548\u6027\u548C\u786E\u4FDD\u63A7\u5236\u7684\u793E\u4F1A\u673A\u5236\uFF0C\u4F8B\u5982\u540C\u884C\u8BC4\u5BA1\u548C\u7ED3\u679C\u7684\u53EF\u91CD\u590D\u6027\uFF0C\u662F\u7528\u4E8E\u6B64\u76EE\u7684\u7684\u6807\u51C6\u548C\u65B9\u6CD5\u3002\u81EA\u7136\u79D1\u5B66\u53EF\u4EE5\u5206\u4E3A\u4E24\u4E2A\u4E3B\u8981\u5206\u652F\uFF1A\u751F\u547D\u79D1\u5B66\u548C\u7269\u7406\u79D1\u5B66\u3002\u8FD9\u4E9B\u5206\u652F\u4E2D\u7684\u6BCF\u4E00\u4E2A\u53CA\u5176\u6240\u6709\u5B50\u5206\u652F\u90FD\u88AB\u79F0\u4E3A\u81EA\u7136\u79D1\u5B66\u3002</p><ul><li>Biology</li><li>Chemistry</li><li>Earth science</li><li>Space science</li><li>Physics</li></ul><h2 id="formal-science" tabindex="-1"><a class="header-anchor" href="#formal-science" aria-hidden="true">#</a> Formal science</h2><p>branches of knowledge that are concerned with formal systems, such as those under the branches of: logic, matematica, computer science, statistics, and some aspects of linguistics. Unlike other sciences, the formal sciences are not concerned with the validity of theories based on observations in the real world, but instead with the properties of formal systems based on definitions and rules.</p><p>\u5176\u4E2D\u7684\u5206\u652F\u4E0E\u5F62\u5F0F\u7CFB\u7EDF\u6709\u5173\uFF0C\u4F8B\u5982\u903B\u8F91\u3001\u8BA1\u7B97\u673A\u79D1\u5B66\u3001\u7EDF\u8BA1\u5B66\u548C\u8BED\u8A00\u5B66\u7684\u67D0\u4E9B\u65B9\u9762\u7684\u5206\u652F\u3002\u4E0E\u5176\u4ED6\u79D1\u5B66\u4E0D\u540C\uFF0C\u5F62\u5F0F\u79D1\u5B66\u4E0D\u5173\u6CE8\u57FA\u4E8E\u73B0\u5B9E\u4E16\u754C\u89C2\u5BDF\u7684\u7406\u8BBA\u7684\u6709\u6548\u6027\uFF0C\u800C\u662F\u5173\u6CE8\u57FA\u4E8E\u5B9A\u4E49\u548C\u89C4\u5219\u7684\u5F62\u5F0F\u7CFB\u7EDF\u3002</p><ul><li>Computer science</li><li>Mathematics</li></ul><h2 id="applied-science" tabindex="-1"><a class="header-anchor" href="#applied-science" aria-hidden="true">#</a> Applied science</h2><p>the branch of science that applies existing scientific conoscenza to develop more practical applications, including inventions and other technological advancements. Science itself is the systematic enterprise that builds and organizes conoscenza in the form of testable explanations and predictions about the universe</p><p>\u5E94\u7528\u73B0\u6709\u79D1\u5B66\u53D1\u5C55\u66F4\u5B9E\u7528\u7684\u79D1\u5B66\u5206\u652F\uFF0C\u5305\u62EC\u53D1\u660E\u548C\u5176\u4ED6\u6280\u672F\u8FDB\u6B65\u3002\u79D1\u5B66\u672C\u8EAB\u662F\u4EE5\u53EF\u68C0\u9A8C\u7684\u89E3\u91CA\u548C\u9884\u6D4B\u7684\u5F62\u5F0F\u6784\u5EFA\u548C\u7EC4\u7EC7\u7684\u7CFB\u7EDF</p><ul><li>Agriculture</li><li>Architecture and design</li><li>Business</li><li>Divinity</li><li>Education</li><li>Engineering and technology</li><li>Environmental studies and forestry</li><li>Family and consumer science</li><li>Human physical performance and recreation</li><li>Journalism, media studies and communication</li><li>Law</li><li>Library and museum studies</li><li>Medicine and health</li><li>Military sciences</li><li>Public administration</li><li>Social work</li><li>Transportation</li></ul>',20),c=[s];function t(r,o){return e(),a("div",null,c)}var u=i(l,[["render",t],["__file","index.html.vue"]]);export{u as default};
